+/* This test verifies that URLs with mostly non-typed visits have their frecency weighted down by 0.5
+ * and thus rank lower in autofill suggestions compared to URLs with typed visits.
+ */
+
+import { PlacesUtils } from "resource://gre/modules/PlacesUtils.sys.mjs";
+import { UrlbarTestUtils } from "resource://testing-common/UrlbarTestUtils.sys.mjs";
+
+add_task(async function test_non_typed_visits_weighting() {
+  // Clean slate
+  await PlacesUtils.bookmarks.eraseEverything();
+  await PlacesUtils.history.clear();
+
+  // Insert URL with mostly non-typed visits (visit_type != 1)
+  let urlNonTyped = "http://example-nontyped.com/";
+  for (let i = 0; i < 10; i++) {
+    await PlacesUtils.history.insert({
+      url: urlNonTyped,
+      visits: [{ date: Date.now() - i * 1000, type: PlacesUtils.history.TYPE_LINK }],
+    });
+  }
+
+  // Insert URL with typed visits (visit_type == 1)
+  let urlTyped = "http://example-typed.com/";
+  for (let i = 0; i < 5; i++) {
+    await PlacesUtils.history.insert({
+      url: urlTyped,
+      visits: [{ date: Date.now() - i * 1000, type: PlacesUtils.history.TYPE_TYPED }],
+    });
+  }
+
+  // Force frecency recalculation
+  await PlacesUtils.history.recalculateFrecency();
+
+  // Query autofill suggestions for "http://example"
+  let context = UrlbarTestUtils.createContext("http://example", { isPrivate: false });
+  let result = await UrlbarTestUtils.getResults(context);
+
+  // Check that urlTyped ranks higher than urlNonTyped due to weighted frecency
+  let typedIndex = result.findIndex(r => r.url == urlTyped);
+  let nonTypedIndex = result.findIndex(r => r.url == urlNonTyped);
+  Assert.ok(typedIndex >= 0, "Typed URL appears in results");
+  Assert.ok(nonTypedIndex >= 0, "Non-typed URL appears in results");
+  Assert.ok(typedIndex < nonTypedIndex, "Typed URL ranks higher than non-typed URL");
+});
